let ores = ['Coal', 'Iron', 'Gold', 'Diamond'];

for (let ore of ores) {
  if (ore === 'Gold') {
    console.log('Found it!');
    break; // Stops here
  }
  console.log('Digging...');
}

for (let i = 0; i < 5; i++) {
  if (i % 2 !== 0) {
    continue; // Skip odd
  }
  console.log(i); // Prints 0, 2, 4
}
